css_snippet:
/* For consistent alignment in data tables and dashboards */
.data-value {
  font-variant-numeric: tabular-nums lining-nums;
}

/* For numbers that blend seamlessly with paragraph text */
.paragraph-with-numbers {
  font-variant-numeric: oldstyle-nums;
}

/* For displaying stacked or diagonal fractions (font support needed) */
.measurement-value {
  font-variant-numeric: stacked-fractions;
}
